-- ========================================
-- Migration 14: Global Medicines Database (Real EAN-13 Barcodes)
-- ========================================
-- المصدر: Base de Données Publique des Médicaments (France)
-- URL: https://base-donnees-publique.medicaments.gouv.fr
-- الترخيص: Open Data (Licence Ouverte)
-- الحجم: 3,699 دواء حقيقي بباركودات CIP-13 (متوافقة مع EAN-13)
-- ========================================

-- جدول قاعدة بيانات الأدوية العالمية
CREATE TABLE IF NOT EXISTS global_medicines (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    barcode VARCHAR(13) UNIQUE NOT NULL,
    name_fr VARCHAR(200) NOT NULL,
    name_ar VARCHAR(200),
    active_ingredient VARCHAR(100),
    brand_name VARCHAR(100),
    dosage_form VARCHAR(100),
    dosage_form_fr VARCHAR(100),
    dosage_form_ar VARCHAR(100),
    route VARCHAR(100),
    strength VARCHAR(100),
    manufacturer VARCHAR(200),
    category VARCHAR(150),
    is_otc BOOLEAN DEFAULT FALSE,
    source VARCHAR(50) DEFAULT 'fr_cis_cip',
    created_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_global_med_barcode ON global_medicines (barcode);
CREATE INDEX IF NOT EXISTS idx_global_med_active ON global_medicines (active_ingredient);
CREATE INDEX IF NOT EXISTS idx_global_med_brand ON global_medicines (brand_name);
CREATE INDEX IF NOT EXISTS idx_global_med_search ON global_medicines USING gin(to_tsvector('simple', name_fr || ' ' || COALESCE(active_ingredient, '') || ' ' || COALESCE(brand_name, '')));

-- إدراج الأدوية

-- Batch 1 (rows 1-500)
ON CONFLICT (barcode) DO NOTHING;

-- Batch 2 (rows 501-1000)
ON CONFLICT (barcode) DO NOTHING;

-- Batch 3 (rows 1001-1500)
ON CONFLICT (barcode) DO NOTHING;

-- Batch 4 (rows 1501-2000)
ON CONFLICT (barcode) DO NOTHING;

-- Batch 5 (rows 2001-2500)
ON CONFLICT (barcode) DO NOTHING;

-- Batch 6 (rows 2501-3000)
ON CONFLICT (barcode) DO NOTHING;

-- Batch 7 (rows 3001-3500)
ON CONFLICT (barcode) DO NOTHING;

-- Batch 8 (rows 3501-3699)
ON CONFLICT (barcode) DO NOTHING;

